const raw = $input.first().json.data;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;

const users = parsed?._embedded?.users ?? [];

const by_id = {};
const by_name = {};

for (const user of users) {
  const rights = user.rights ?? {};

  const clean = {
    id: user.id,
    name: user.name,
    email: user.email,
    lang: user.lang ?? null,

    // Flags de status
    is_admin: rights.is_admin ?? false,
    is_active: rights.is_active ?? true,
    is_free: rights.is_free ?? false,

    // Grupos e papéis
    group_id: rights.group_id ?? null,
    role_id: rights.role_id ?? null,

    // Acesso a módulos
    mail_access: rights.mail_access ?? false,
    catalog_access: rights.catalog_access ?? false,
    files_access: rights.files_access ?? false,

    // Permissões gerais por entidade
    permissions: {
      leads: rights.leads ?? null,
      contacts: rights.contacts ?? null,
      companies: rights.companies ?? null,
      tasks: rights.tasks ?? null,
    },

    // Permissões granulares por etapa/pipeline
    status_rights: rights.status_rights ?? [],
    catalog_rights: rights.catalog_rights ?? [],
    custom_fields_rights: rights.custom_fields_rights ?? null,
  };

  by_id[String(user.id)] = clean;

  const nameKey = user.name?.toLowerCase().trim().replace(/\s+/g, '_');
  if (nameKey) by_name[nameKey] = clean;
}

const result = {
  total: users.length,
  updated_at: new Date().toISOString(),
  users: Object.values(by_id),
  by_id,
  by_name,
};

return [{ json: result }];
